import { SlashCommandBuilder } from 'discord.js';
import { getPlayer, setAP } from '../utils/dataManager.js';
import { createSuccessEmbed, createErrorEmbed } from '../utils/embeds.js';
import { isAdmin } from '../utils/adminCheck.js';

export const data = new SlashCommandBuilder()
    .setName('set-ap')
    .setDescription('[АДМИН] Установить AP игрока')
    .addUserOption(option =>
        option.setName('user')
            .setDescription('Игрок для изменения')
            .setRequired(true))
    .addIntegerOption(option =>
        option.setName('amount')
            .setDescription('Количество AP')
            .setRequired(true));

export async function execute(interaction) {
    if (!isAdmin(interaction.member)) {
        return interaction.reply({
            embeds: [createErrorEmbed('Доступ запрещен', 'Эта команда доступна только администраторам.')],
            ephemeral: true
        });
    }

    const targetUser = interaction.options.getUser('user');
    const amount = interaction.options.getInteger('amount');
    const playerId = targetUser.id;

    const player = getPlayer(playerId);

    if (!player) {
        return interaction.reply({
            embeds: [createErrorEmbed('Не зарегистрирован', `Игрок не зарегистрирован.`)],
            ephemeral: true
        });
    }

    if (amount < 0) {
        return interaction.reply({
            embeds: [createErrorEmbed('Некорректное значение', 'AP не может быть отрицательным.')],
            ephemeral: true
        });
    }

    const success = setAP(playerId, amount, interaction.user.id);

    if (success) {
        return interaction.reply({
            embeds: [createSuccessEmbed('AP обновлено', 
                `Установлено **${amount} AP** для игрока **${player.character_name || player.username}**`)]
        });
    } else {
        return interaction.reply({
            embeds: [createErrorEmbed('Ошибка', 'Не удалось обновить AP.')],
            ephemeral: true
        });
    }
}

utils/progressBar.js.content:
export function progressBar(current, max, length = 20) {
    const percentage = Math.min(100, Math.max(0, (current / max) * 100));
    const filledBlocks = Math.floor((percentage / 100) * length);
    const emptyBlocks = length - filledBlocks;

    const filled = '█'.repeat(filledBlocks);
    const empty = '░'.repeat(emptyBlocks);

    return `${filled}${empty} ${percentage.toFixed(0)}% (${current}/${max})`;
}

export function getAPProgress(currentAP) {
    const nextMilestone = Math.ceil(currentAP / 100) * 100;
    const previousMilestone = Math.floor(currentAP / 100) * 100;
    const progressInCurrentRange = currentAP - previousMilestone;

    return {
        current: progressInCurrentRange,
        max: 100,
        nextMilestone,
        techniques: Math.floor(currentAP / 100)
    };
}

export function getSPRank(sp) {
    if (sp >= 2500) return { rank: 'Master', color: 0xFF0000 };
    if (sp >= 1000) return { rank: 'Expert', color: 0xFF6B00 };
    if (sp >= 350) return { rank: 'Owner', color: 0xFFD700 };
    return { rank: 'Novice', color: 0x808080 };
}

