import { SlashCommandBuilder } from 'discord.js';
import { getPlayer, createPlayer } from '../utils/dataManager.js';
import { createSuccessEmbed, createErrorEmbed } from '../utils/embeds.js';

export const data = new SlashCommandBuilder()
    .setName('register')
    .setDescription('Зарегистрироваться в системе')
    .addStringOption(option =>
        option.setName('character_name')
            .setDescription('Имя вашего персонажа')
            .setRequired(true))
    .addAttachmentOption(option =>
        option.setName('avatar')
            .setDescription('Аватар персонажа (необязательно)')
            .setRequired(false));

export async function execute(interaction) {
    const playerId = interaction.user.id;
    const username = interaction.user.username;
    const characterName = interaction.options.getString('character_name');
    const avatarAttachment = interaction.options.getAttachment('avatar');

    const existingPlayer = getPlayer(playerId);

    if (existingPlayer) {
        return interaction.reply({
            embeds: [createErrorEmbed('Уже зарегистрирован', 'Вы уже зарегистрированы в системе!')],
            ephemeral: true
        });
    }

    if (characterName.length < 2 || characterName.length > 32) {
        return interaction.reply({
            embeds: [createErrorEmbed('Некорректное имя', 'Имя персонажа должно быть от 2 до 32 символов.')],
            ephemeral: true
        });
    }

    let avatarUrl = null;
    if (avatarAttachment) {
        if (avatarAttachment.contentType && avatarAttachment.contentType.startsWith('image/')) {
            avatarUrl = avatarAttachment.url;
        }
    }

    const success = createPlayer(playerId, username, characterName, avatarUrl);

    if (success) {
        return interaction.reply({
            embeds: [createSuccessEmbed('Регистрация завершена', 
                `Добро пожаловать, **${characterName}**!\n\nУдачи в приключениях! 🚀`)]
        });
    } else {
        return interaction.reply({
            embeds: [createErrorEmbed('Ошибка регистрации', 'Произошла ошибка при регистрации. Попробуйте снова.')],
            ephemeral: true
        });
    }
}

commands/social-rp.js.content:
import { SlashCommandBuilder } from 'discord.js';
import { getPlayer, addAP } from '../utils/dataManager.js';
import { checkCooldown } from '../utils/cooldowns.js';
import { createSuccessEmbed, createErrorEmbed } from '../utils/embeds.js';
import { progressBar, getAPProgress } from '../utils/progressBar.js';

const SOCIALRP_COOLDOWN = 12 * 60 * 60 * 1000;
const SOCIALRP_AP_REWARD = 20;

export const data = new SlashCommandBuilder()
    .setName('social-rp')
    .setDescription('Социальное взаимодействие для получения AP (20 AP, кулдаун 12 часов)')
    .addStringOption(option =>
        option.setName('text')
            .setDescription('Текст взаимодействия')
            .setRequired(true));

export async function execute(interaction) {
    const playerId = interaction.user.id;
    const rpText = interaction.options.getString('text');

    let player = getPlayer(playerId);

    if (!player) {
        return interaction.reply({
            embeds: [createErrorEmbed('Не зарегистрирован', 'Сначала зарегистрируйтесь командой `/register`!')],
            ephemeral: true
        });
    }

    if (rpText.length < 50) {
        return interaction.reply({
            embeds: [createErrorEmbed('Текст слишком короткий', 'Текст должен содержать минимум 50 символов.')],
            ephemeral: true
        });
    }

    const cooldownCheck = checkCooldown(player.last_socialrp_timestamp, SOCIALRP_COOLDOWN);
    if (cooldownCheck.onCooldown) {
        return interaction.reply({
            embeds: [createErrorEmbed('Кулдаун', `Следующее взаимодействие доступно через **${cooldownCheck.remainingFormatted}**`)],
            ephemeral: true
        });
    }

    const newAP = addAP(playerId, SOCIALRP_AP_REWARD, 'socialrp');

    if (newAP === false) {
        return interaction.reply({
            embeds: [createErrorEmbed('Ошибка', 'Не удалось добавить AP. Попробуйте снова.')],
            ephemeral: true
        });
    }

    const apProgress = getAPProgress(newAP);
    const progressText = progressBar(apProgress.current, apProgress.max, 20);

    const embed = createSuccessEmbed('Взаимодействие завершено!', 
        `Вы получили **${SOCIALRP_AP_REWARD} AP**!\n\n` +
        `**Всего AP:** ${newAP}\n` +
        `**Техник разблокировано:** ${apProgress.techniques}\n\n` +
        `**Прогресс к следующей технике:**\n${progressText}`
    );

    if (newAP >= 1000) {
        embed.setDescription(embed.data.description + '\n\n🌟 **Вы достигли 1000 AP! Avatar/Embodiment доступен!**');
    }

    return interaction.reply({ embeds: [embed] });
}

